// Signal Waveform -- glowing phosphor oscilloscope on a gold graticule.
uniform vec4 uWave;    // x=traces, y=frequency, z=amplitude, w=time(=absTime*Speed)
uniform vec4 uSweep;   // x=sweepRate, y=afterglow, z=ptpRate, w=lineWidth
uniform vec4 uLook;    // x=graticule, y=harmonics, z=glow, w=absTime
out vec4 fragColor;
const float PI = 3.14159265;

// a rich broadcast-like signal: summed detuned harmonics, per-trace seeded
float signal(float x, float seed, float freq, float harm, float t){
    float v = 0.0;
    v += sin(x*freq + t + seed);
    v += 0.5  * sin(x*freq*2.03 + t*1.3 + seed*1.7);
    v += 0.33 * sin(x*freq*3.97 + t*0.8 + seed*2.3) * harm;
    v += 0.22 * sin(x*freq*7.1  - t*1.1 + seed*0.5) * harm;
    return v / 2.0;   // ~[-1,1]
}

void main(){
    vec2 uv = vUV.st;
    float aspect = uTDOutputInfo.res.z / uTDOutputInfo.res.w;
    vec2 p = uv;

    vec3 col = vec3(0.010, 0.012, 0.016);   // near-black scope ground

    // --- gold graticule grid (vectorscope/waveform-monitor look) ---
    float grat = uLook.x;
    vec2 g = abs(fract(uv * vec2(16.0, 9.0)) - 0.5);
    float grid = smoothstep(0.49, 0.5, max(g.x, g.y));
    // brighter center crosshair
    float cross = smoothstep(0.004, 0.0, abs(uv.y-0.5)) + smoothstep(0.004,0.0,abs(uv.x-0.5));
    col += vec3(0.20, 0.16, 0.05) * grid * 0.18 * grat;
    col += vec3(0.35, 0.28, 0.08) * cross * 0.25 * grat;

    // --- traces: green audio, cyan video, magenta chroma ---
    float nT = clamp(uWave.x, 1.0, 3.0);
    float freq = uWave.y;
    float amp  = uWave.z;
    float harm = uLook.y;
    float t    = uWave.w;
    float lw   = uSweep.w;
    float glow = uLook.z;

    vec3 traceCols[3];
    traceCols[0] = vec3(0.18, 1.00, 0.40);   // phosphor green (audio)
    traceCols[1] = vec3(0.00, 0.85, 1.00);   // cyan (video luma)
    traceCols[2] = vec3(1.00, 0.18, 0.60);   // magenta (chroma)
    float yCenters[3]; yCenters[0]=0.5; yCenters[1]=0.72; yCenters[2]=0.30;
    float seeds[3];    seeds[0]=0.0;  seeds[1]=2.1;  seeds[2]=4.7;
    float amps[3];     amps[0]=1.0;   amps[1]=0.55;  amps[2]=0.45;

    // sweeping playhead position (wraps 0..1), white-hot leading edge
    float head = fract(uLook.w * uSweep.x);
    float ageBehind = head - uv.x;                 // distance behind the head along x
    if(ageBehind < 0.0) ageBehind += 1.0;          // wrap
    float persistence = exp(-ageBehind * mix(8.0, 1.5, uSweep.y));  // afterglow falloff

    const int MAXT = 3;
    for(int i=0;i<MAXT;i++){
        if(float(i) >= nT) break;
        float yc = yCenters[i];
        float s  = signal((uv.x*2.0-1.0)*aspect, seeds[i], freq, harm, t);
        float y  = yc + s * amp * amps[i] * 0.16;
        float d  = abs(uv.y - y);
        float line = smoothstep(lw, 0.0, d);                 // crisp core
        float halo = smoothstep(lw*8.0*glow, 0.0, d) * 0.35; // soft glow
        float bright = (line + halo) * persistence;
        // white-hot at the playhead, color in the tail
        vec3 c = mix(traceCols[i], vec3(1.0), line * smoothstep(0.06, 0.0, ageBehind));
        col += c * bright;
    }

    // --- PTP sync flash: a steady beat + a thin vertical sync bar wipe ---
    float beat = fract(uLook.w * uSweep.z);
    float flash = pow(max(0.0, 1.0 - beat*4.0), 3.0);
    col += vec3(0.05, 0.08, 0.10) * flash;                  // whole-screen breath
    float bar = smoothstep(0.006, 0.0, abs(uv.x - beat));   // sync bar wipes l->r
    col += vec3(0.10, 0.20, 0.24) * bar * 0.6;

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Bloom + scanline + grain + occasional PTP-synced RGB-split finish.
uniform vec4 uFinish;   // x=bloom, y=threshold, z=rgbSplit, w=ptpTime
out vec4 fragColor;

float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }

void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;   // 1/w,1/h

    // RGB chromatic separation, pulsed on the PTP beat (broadcast authenticity)
    float beat = fract(uFinish.w);
    float ev = pow(max(0.0, 1.0 - beat*6.0), 4.0);          // brief event right on the tick
    float sp = uFinish.z * (0.0015 + 0.004*ev);
    vec3 src;
    src.r = texture(sTD2DInputs[0], uv + vec2(sp, 0.0)).r;
    src.g = texture(sTD2DInputs[0], uv).g;
    src.b = texture(sTD2DInputs[0], uv - vec2(sp, 0.0)).b;

    // bright-pass bloom, bounded taps
    float thr = uFinish.y;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 6;
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/16.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*2.2).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    vec3 col = src + (sum/max(wsum,1e-4)) * uFinish.x;

    // scanlines + grain
    float scan = 0.94 + 0.06*sin(uv.y * uTDOutputInfo.res.w * 3.14159);
    col *= scan;
    col += (hash21(uv*uTDOutputInfo.res.zw + beat*97.0)-0.5) * 0.015;

    fragColor = vec4(col, 1.0);
}
